from kafka import KafkaAdminClient
from kafka.admin import NewTopic
import argparse

def main():
    parser = argparse.ArgumentParser(description='Manage topics in a Kafka cluster')
    parser.add_argument('--topic', required=True, help="The name of the topic to be created")
    parser.add_argument('--bootstrap-server', default="localhost:9092", help="The bootstrap server URL")
    args = parser.parse_args()

    admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_server)
    
    topic = NewTopic(name=args.topic, num_partitions=1, replication_factor=1)

    try:
        admin_client.create_topics([topic])
        print("Created topic", args.topic)
    except Exception as e:
        print("Failed to create topic", args.topic, "due to: ", str(e))
        
if __name__ == '__main__':
    main()